"use client";

import { useParams, useRouter } from "next/navigation";
import { useProducts } from "@/lib/ProductContext";
import { useCart } from "@/lib/CartContext"; // Importar Carrinho
import { useAuth } from "@/lib/AuthProvider"; // Importar Autenticação
import { ArrowLeft, ShoppingBag, ShieldCheck, Truck, Star } from "lucide-react";
import { FloatingCart } from "@/components/FloatingCart";
export default function ProductDetails() {
  const { id } = useParams();
  const { products } = useProducts();
  const { addToCart } = useCart();
  const { user } = useAuth();
  const router = useRouter();
  
  const product = products.find(p => p.id === Number(id));

  if (!product) return <div className="p-20 text-center font-bold">Produto não encontrado.</div>;

  // FUNÇÃO: ADICIONAR AO CARRINHO
  const handleAddToCart = () => {
    addToCart({
      id: product.id,
      name: product.name,
      price: product.price,
      image: product.image,
      quantity: 1
    });
    // Opcional: feedback visual ou abrir lateral do carrinho
  };

  // FUNÇÃO: COMPRAR AGORA (Lógica de Login inclusa)
  const handleBuyNow = () => {
    // Primeiro adicionamos ao carrinho
    addToCart({
      id: product.id,
      name: product.name,
      price: product.price,
      image: product.image,
      quantity: 1
    });

    // Verificamos se está logado
    if (!user) {
      // Se não tem conta, vai para o login e salva o retorno para o carrinho
      router.push("/auth/login?returnTo=/products/carrinho");
    } else {
      // Se tem conta, vai direto para o carrinho/checkout
      router.push("/products/carrinho");
    }
  };

  return (
    <div className="min-h-screen bg-white font-sans">
      <div className="max-w-7xl mx-auto px-6 py-12">
        <button 
          onClick={() => router.back()} 
          className="flex items-center gap-2 mb-10 text-gray-500 hover:text-black transition-all group"
        >
          <ArrowLeft size={20} className="group-hover:-translate-x-1 transition-transform" /> 
          <span className="font-bold uppercase text-[10px] tracking-widest">Voltar à Loja</span>
        </button>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-16">
          {/* Imagem */}
          <div className="bg-[#F8F8F8] rounded-[60px] overflow-hidden flex items-center justify-center p-12 border border-gray-50">
            <img 
              src={product.image} 
              alt={product.name} 
              className="w-full h-auto max-h-[500px] object-contain hover:scale-105 transition-transform duration-700" 
            />
          </div>

          {/* Info */}
          <div className="flex flex-col justify-center">
            <span className="text-[#9C7C50] font-black text-[10px] uppercase tracking-[0.3em] mb-4">
              {product.category}
            </span>
            <h1 className="text-5xl font-black text-gray-900 mb-4 leading-tight">
              {product.name}
            </h1>
            
            <div className="flex items-center gap-2 mb-6">
               <div className="flex text-[#C5A267]">
                  <Star size={14} fill="currentColor" />
                  <Star size={14} fill="currentColor" />
                  <Star size={14} fill="currentColor" />
                  <Star size={14} fill="currentColor" />
                  <Star size={14} fill="currentColor" />
               </div>
               <span className="text-xs text-gray-400 font-bold">(4.9/5.0)</span>
            </div>

            <p className="text-3xl font-black text-gray-800 mb-8">
              AOA {product.price.toLocaleString()}
            </p>
            
            <div className="prose prose-sm text-gray-500 mb-10 leading-relaxed border-l-2 border-[#9C7C50]/20 pl-6">
              {product.description || "Este produto premium da Nani Cosmético foi formulado com os melhores ingredientes para garantir resultados excepcionais no seu cuidado diário."}
            </div>

            {/* BOTÕES DE AÇÃO */}
            <div className="flex flex-col gap-4 mb-10">
              <button 
                onClick={handleBuyNow}
                className="w-full bg-black text-white py-6 rounded-3xl font-black uppercase tracking-widest shadow-2xl hover:bg-gray-800 transition-all active:scale-95"
              >
                Comprar Agora
              </button>
              
              <button 
                onClick={handleAddToCart}
                className="w-full border-2 border-[#9C7C50] text-[#9C7C50] py-6 rounded-3xl font-black uppercase tracking-widest hover:bg-[#9C7C50] hover:text-white transition-all active:scale-95 flex items-center justify-center gap-3"
              >
                <ShoppingBag size={20} />
                Adicionar ao Carrinho
              </button>
            </div>

            {/* Selos de Confiança */}
            <div className="grid grid-cols-2 gap-6 border-t border-gray-100 pt-10">
              <div className="flex items-center gap-4">
                <div className="p-3 bg-gray-50 rounded-2xl text-[#9C7C50]"><Truck size={20}/></div>
                <div>
                  <p className="text-[10px] font-black uppercase text-gray-900">Entrega</p>
                  <p className="text-[9px] font-bold text-gray-400">Em toda Luanda</p>
                </div>
              </div>
              <div className="flex items-center gap-4">
                <div className="p-3 bg-gray-50 rounded-2xl text-[#9C7C50]"><ShieldCheck size={20}/></div>
                <div>
                  <p className="text-[10px] font-black uppercase text-gray-900">Segurança</p>
                  <p className="text-[9px] font-bold text-gray-400">Original Garantido</p>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}